"use client";

/* =============================================================================
   AlgeriaGlobe — Half-globe over Algeria, with Algeria in gray dots
   -----------------------------------------------------------------------------
   - Tighter camera framing — Algeria fills ~30% of the canvas width
   - Half-visible globe: sphere center sits at canvas bottom edge, only the
     upper hemisphere is shown, horizon arcs across the top
   - World dots in red, Algeria's own dots in LIGHT GRAY so it stands out as
     the focal region (with a subtle red backdrop ring to make sure the
     gray reads against the cream background)
   - Slow continuous rotation around the polar axis
   - 8 city pins, travel arcs, click-to-cascade interaction preserved
   ============================================================================= */

